import type { CareerQuestion } from "./rrt-questions";

export const psychotherapistQuestionsBatch2: CareerQuestion[] = [
  { id: "rp-501", stem: "A client presents with intrusive thoughts about contamination and repetitive hand-washing. Which therapeutic approach has the strongest evidence base for this presentation?", options: ["Exposure and Response Prevention (ERP)","Psychodynamic therapy","Person-centered therapy","Solution-focused brief therapy"], correctIndex: 0, rationale: "ERP is the gold-standard treatment for OCD. It involves gradual exposure to feared stimuli while preventing compulsive responses, leading to habituation and reduced anxiety.", difficulty: 2, category: "Therapeutic Modalities", topic: "Evidence-Based Treatments" },
  { id: "rp-502", stem: "In Dialectical Behavior Therapy, the concept of 'dialectics' refers to:", options: ["Balancing acceptance and change simultaneously","Challenging irrational beliefs through logic","Free association of unconscious material","Systematic desensitization to feared stimuli"], correctIndex: 0, rationale: "DBT's core dialectic is the synthesis of acceptance (validation) and change (behavioral skills). This balance is fundamental to treating clients with emotion dysregulation.", difficulty: 2, category: "Therapeutic Modalities", topic: "DBT" },
  { id: "rp-503", stem: "A therapist notices a client consistently arrives late and avoids discussing childhood experiences. From a psychodynamic perspective, this behavior most likely represents:", options: ["Resistance","Transference","Countertransference","Projection"], correctIndex: 0, rationale: "Resistance refers to unconscious defenses that prevent awareness of threatening thoughts or feelings. Avoidance of painful topics and lateness are classic forms of resistance in psychodynamic therapy.", difficulty: 3, category: "Therapeutic Modalities", topic: "Psychodynamic Therapy" },
  { id: "rp-504", stem: "Which DBT skill module teaches clients to tolerate distress without making the situation worse?", options: ["Distress Tolerance","Emotion Regulation","Interpersonal Effectiveness","Core Mindfulness"], correctIndex: 0, rationale: "Distress Tolerance skills help clients survive crises without resorting to destructive behaviors. Techniques include TIPP, ACCEPTS, and radical acceptance.", difficulty: 1, category: "Therapeutic Modalities", topic: "DBT" },
  { id: "rp-505", stem: "A cognitive-behavioral therapist identifies that a client catastrophizes minor setbacks. The therapist's next step should be to:", options: ["Help the client examine evidence for and against the catastrophic thought","Explore the client's early childhood attachment patterns","Use paradoxical intention to amplify the catastrophizing","Focus solely on behavioral activation without addressing thoughts"], correctIndex: 0, rationale: "Cognitive restructuring in CBT involves examining evidence for and against automatic thoughts. This helps clients develop more balanced, realistic appraisals.", difficulty: 2, category: "Therapeutic Modalities", topic: "CBT" },
  { id: "rp-506", stem: "In Motivational Interviewing, 'sustain talk' refers to:", options: ["Client language favoring the status quo and against change","Therapist statements supporting continued treatment","Client statements about maintaining therapeutic gains","Discussion about long-term treatment sustainability"], correctIndex: 0, rationale: "Sustain talk is client speech that favors maintaining current behavior patterns. MI therapists respond by rolling with resistance rather than confronting it directly.", difficulty: 2, category: "Therapeutic Modalities", topic: "Motivational Interviewing" },
  { id: "rp-507", stem: "A therapist using EMDR asks the client to track finger movements while recalling a traumatic memory. This technique is part of which phase?", options: ["Desensitization","Assessment","Installation","Body Scan"], correctIndex: 0, rationale: "The desensitization phase (Phase 4) involves bilateral stimulation while the client focuses on the traumatic memory, continuing until the SUD level decreases.", difficulty: 3, category: "Therapeutic Modalities", topic: "EMDR" },
  { id: "rp-508", stem: "Carl Rogers identified three core conditions for therapeutic change. Which is NOT one of them?", options: ["Systematic reinforcement","Unconditional positive regard","Congruence","Empathic understanding"], correctIndex: 0, rationale: "Rogers' three core conditions are unconditional positive regard, congruence (genuineness), and empathic understanding. Systematic reinforcement is a behavioral technique.", difficulty: 1, category: "Therapeutic Modalities", topic: "Person-Centered Therapy" },
  { id: "rp-509", stem: "In Acceptance and Commitment Therapy (ACT), 'cognitive defusion' involves:", options: ["Changing the relationship to thoughts rather than changing their content","Systematically challenging irrational beliefs","Suppressing unwanted thoughts through distraction","Replacing negative thoughts with positive affirmations"], correctIndex: 0, rationale: "Cognitive defusion in ACT helps clients observe thoughts as mental events rather than literal truths. This reduces the impact of distressing thoughts without trying to eliminate them.", difficulty: 3, category: "Therapeutic Modalities", topic: "ACT" },
  { id: "rp-510", stem: "Which therapeutic approach is most appropriate for a 4-year-old child who witnessed domestic violence?", options: ["Play therapy","Cognitive Processing Therapy","Rational Emotive Behavior Therapy","Existential therapy"], correctIndex: 0, rationale: "Play therapy is developmentally appropriate for young children who lack the verbal and cognitive skills for talk-based therapies. It allows symbolic expression of traumatic experiences.", difficulty: 1, category: "Therapeutic Modalities", topic: "Child Therapy" },
  { id: "rp-511", stem: "A therapist practicing Gestalt therapy asks a client to speak to an empty chair representing their deceased parent. This technique is called:", options: ["Empty chair technique","Free association","Systematic desensitization","Thought stopping"], correctIndex: 0, rationale: "The empty chair technique is a core Gestalt intervention that facilitates dialogue with absent persons or aspects of self, promoting awareness and resolution of unfinished business.", difficulty: 1, category: "Therapeutic Modalities", topic: "Gestalt Therapy" },
  { id: "rp-512", stem: "In narrative therapy, 'externalizing the problem' means:", options: ["Separating the problem from the person's identity","Blaming external factors for the client's issues","Referring the client to another provider","Discussing problems only in terms of environmental causes"], correctIndex: 0, rationale: "Externalizing separates the problem from the person ('The person is not the problem; the problem is the problem'). This reduces shame and creates space for agency.", difficulty: 2, category: "Therapeutic Modalities", topic: "Narrative Therapy" },
  { id: "rp-513", stem: "A client with borderline personality disorder is in the first stage of DBT treatment. The primary treatment target is:", options: ["Life-threatening behaviors","Improving quality of life","Processing past trauma","Building self-respect"], correctIndex: 0, rationale: "Stage 1 of DBT prioritizes targets hierarchically: (1) life-threatening behaviors, (2) therapy-interfering behaviors, (3) quality-of-life-interfering behaviors, (4) skills acquisition.", difficulty: 2, category: "Therapeutic Modalities", topic: "DBT" },
  { id: "rp-514", stem: "Which intervention is most consistent with a solution-focused brief therapy approach?", options: ["Asking the miracle question","Analyzing defense mechanisms","Conducting a functional behavioral analysis","Exploring unconscious conflicts"], correctIndex: 0, rationale: "The miracle question ('If a miracle happened overnight and the problem was solved, what would be different?') is a signature SFBT technique that helps clients envision desired outcomes.", difficulty: 1, category: "Therapeutic Modalities", topic: "SFBT" },
  { id: "rp-515", stem: "In Cognitive Processing Therapy for PTSD, 'stuck points' are:", options: ["Maladaptive beliefs about the trauma that maintain PTSD symptoms","Points where the client refuses to continue treatment","Moments of dissociation during session","Therapeutic plateaus in symptom reduction"], correctIndex: 0, rationale: "Stuck points are problematic beliefs about the trauma (e.g., 'It was my fault') that prevent natural recovery. CPT targets these through Socratic questioning and worksheets.", difficulty: 3, category: "Therapeutic Modalities", topic: "Trauma Therapy" },
  { id: "rp-516", stem: "A family therapist observes that whenever the identified patient improves, another family member develops symptoms. This pattern is best described as:", options: ["Homeostasis","Enmeshment","Triangulation","Differentiation"], correctIndex: 0, rationale: "Homeostasis is the family system's tendency to maintain equilibrium. When one member changes, the system may compensate through symptom development in another member.", difficulty: 3, category: "Therapeutic Modalities", topic: "Family Therapy" },
  { id: "rp-517", stem: "A therapist discovers that a current client is the business partner of another current client. Neither is aware of the other's treatment. The therapist should:", options: ["Consult with a colleague or ethics board about managing the dual relationship","Immediately terminate one client","Disclose each client's treatment to the other","Continue without addressing the situation"], correctIndex: 0, rationale: "When potential conflicts arise, consultation is the ethical first step. The therapist must consider confidentiality, potential harm, and whether continued treatment of both is feasible.", difficulty: 3, category: "Ethics & Professional Practice", topic: "Dual Relationships" },
  { id: "rp-518", stem: "A client reveals plans to harm a specific, identifiable person. The therapist's primary ethical and legal obligation is to:", options: ["Take reasonable steps to protect the intended victim, which may include warning the victim and/or notifying authorities","Maintain confidentiality and continue exploring the client's feelings","Document the threat but take no action until it occurs","Refer the client to a psychiatrist immediately"], correctIndex: 0, rationale: "The duty to warn/protect (Tarasoff) overrides confidentiality when a client poses a serious threat to an identifiable person. Specific steps vary by jurisdiction.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Duty to Warn" },
  { id: "rp-519", stem: "Informed consent in psychotherapy must include all of the following EXCEPT:", options: ["A guarantee of treatment outcomes","Limits of confidentiality","The therapist's qualifications","Potential risks and benefits of treatment"], correctIndex: 0, rationale: "Informed consent includes explanation of treatment, risks/benefits, alternatives, confidentiality limits, and therapist qualifications. Outcomes cannot be guaranteed.", difficulty: 1, category: "Ethics & Professional Practice", topic: "Informed Consent" },
  { id: "rp-520", stem: "A therapist begins experiencing strong romantic feelings toward a client. The most ethical course of action is to:", options: ["Seek consultation or personal therapy to address the feelings","Act on the feelings if the client reciprocates","Terminate the client immediately without explanation","Ignore the feelings and continue treatment as usual"], correctIndex: 0, rationale: "Countertransference feelings are normal but must be managed ethically. Consultation and/or personal therapy help the therapist process these feelings without harming the client.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Countertransference" },
  { id: "rp-521", stem: "A minor client (age 14) discloses marijuana use. The parents demand to know what their child discusses in therapy. The therapist should:", options: ["Discuss with the minor what general information can be shared while protecting therapeutic confidentiality within legal requirements","Share all session content with the parents immediately","Refuse to communicate with the parents entirely","Tell the parents about the marijuana use without the client's knowledge"], correctIndex: 0, rationale: "With adolescents, therapists balance parental rights with the minor's need for confidentiality. Best practice involves discussing with the minor what can be shared and involving them in the process.", difficulty: 3, category: "Ethics & Professional Practice", topic: "Confidentiality with Minors" },
  { id: "rp-522", stem: "According to most professional ethics codes, a therapist may terminate treatment when:", options: ["The client is no longer benefiting and the therapist has made appropriate referrals","The client disagrees with the therapist's political views","The client's insurance has lapsed but the client wants to continue","The therapist finds the client's problems boring"], correctIndex: 0, rationale: "Ethical termination occurs when the client no longer needs or benefits from services. The therapist must provide referrals and avoid abandonment.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Termination" },
  { id: "rp-523", stem: "A therapist in a small rural community discovers that the only available AA sponsor for a client is the therapist's neighbor. This situation exemplifies:", options: ["An unavoidable multiple relationship requiring careful management","A clear ethics violation requiring immediate termination","A reason to refuse treatment entirely","An insignificant boundary concern"], correctIndex: 0, rationale: "In small communities, some multiple relationships are unavoidable. Ethical practice involves acknowledging the situation, setting clear boundaries, documenting, and consulting.", difficulty: 3, category: "Ethics & Professional Practice", topic: "Rural Ethics" },
  { id: "rp-524", stem: "Which ethical principle requires therapists to practice within the boundaries of their competence?", options: ["Competence","Beneficence","Justice","Fidelity"], correctIndex: 0, rationale: "Competence requires therapists to provide services only within the boundaries of their education, training, supervised experience, and professional credentials.", difficulty: 1, category: "Ethics & Professional Practice", topic: "Core Principles" },
  { id: "rp-525", stem: "A therapist receives a subpoena for client records. The appropriate first step is to:", options: ["Consult with an attorney and notify the client","Immediately release all records to comply","Destroy the relevant records","Ignore the subpoena until a court order is issued"], correctIndex: 0, rationale: "A subpoena does not automatically require disclosure. The therapist should consult legal counsel, notify the client, and potentially assert privilege on the client's behalf.", difficulty: 3, category: "Ethics & Professional Practice", topic: "Legal Issues" },
  { id: "rp-526", stem: "A client with schizophrenia presents with flat affect, social withdrawal, and poverty of speech. These symptoms are classified as:", options: ["Negative symptoms","Positive symptoms","Cognitive symptoms","Disorganized symptoms"], correctIndex: 0, rationale: "Negative symptoms involve deficits: flat affect, alogia (poverty of speech), avolition, anhedonia, and social withdrawal. Positive symptoms include hallucinations and delusions.", difficulty: 1, category: "Clinical Assessment", topic: "Psychopathology" },
  { id: "rp-527", stem: "During a mental status examination, the examiner notes that a client's speech rapidly shifts between loosely connected topics. This is documented as:", options: ["Flight of ideas","Circumstantiality","Perseveration","Neologism"], correctIndex: 0, rationale: "Flight of ideas involves rapid shifting between topics with loose associations. Circumstantiality is overly detailed but eventually reaches the point. Perseveration is repetitive return to the same topic.", difficulty: 2, category: "Clinical Assessment", topic: "Mental Status Exam" },
  { id: "rp-528", stem: "A client scores 28 on the PHQ-9. This indicates:", options: ["Severe depression","Mild depression","Moderate anxiety","No significant symptoms"], correctIndex: 0, rationale: "PHQ-9 scores: 0-4 minimal, 5-9 mild, 10-14 moderate, 15-19 moderately severe, 20-27 severe depression. A score of 28 exceeds the severe threshold.", difficulty: 2, category: "Clinical Assessment", topic: "Screening Tools" },
  { id: "rp-529", stem: "Which assessment tool is specifically designed to measure trauma symptoms in children ages 3-18?", options: ["UCLA PTSD Reaction Index","Beck Depression Inventory-II","CAGE questionnaire","MMPI-2"], correctIndex: 0, rationale: "The UCLA PTSD Reaction Index is validated for children and adolescents ages 3-18. BDI-II measures depression in adults. CAGE screens for alcohol. MMPI-2 is personality assessment.", difficulty: 3, category: "Clinical Assessment", topic: "Screening Tools" },
  { id: "rp-530", stem: "A client presents with depressed mood, weight gain, hypersomnia, and heavy feeling in extremities. This pattern is most consistent with:", options: ["Major depressive disorder with atypical features","Major depressive disorder with melancholic features","Persistent depressive disorder","Bipolar II disorder"], correctIndex: 0, rationale: "Atypical features include mood reactivity, weight gain/increased appetite, hypersomnia, leaden paralysis, and rejection sensitivity. Melancholic features include weight loss, insomnia, and worse mood in the morning.", difficulty: 3, category: "Clinical Assessment", topic: "Mood Disorders" },
  { id: "rp-531", stem: "The GAF (Global Assessment of Functioning) scale score of 45 indicates:", options: ["Serious symptoms or serious impairment in social, occupational, or school functioning","Superior functioning with no symptoms","Mild symptoms with generally good functioning","Persistent danger of harming self or others"], correctIndex: 0, rationale: "GAF 41-50 indicates serious symptoms (e.g., suicidal ideation, severe obsessional rituals) or serious impairment in functioning. GAF 1-10 indicates persistent danger.", difficulty: 2, category: "Clinical Assessment", topic: "Functional Assessment" },
  { id: "rp-532", stem: "A client experiencing derealization would most likely report:", options: ["Feeling that the world around them is unreal, dreamlike, or distorted","Hearing voices commanding them to act","Inability to recall important autobiographical information","Excessive worry about multiple life domains"], correctIndex: 0, rationale: "Derealization involves experiencing the external world as unreal, foggy, or dreamlike. Depersonalization involves feeling detached from one's own body or mental processes.", difficulty: 2, category: "Clinical Assessment", topic: "Dissociative Symptoms" },
  { id: "rp-533", stem: "Which diagnostic criterion distinguishes Generalized Anxiety Disorder from other anxiety disorders?", options: ["Excessive worry about multiple events or activities occurring more days than not for at least 6 months","Fear of specific objects or situations","Recurrent unexpected panic attacks","Anxiety specifically related to social evaluation"], correctIndex: 0, rationale: "GAD is characterized by pervasive, excessive worry about multiple domains (work, health, finances) for at least 6 months, distinguishing it from specific phobia, panic disorder, and social anxiety.", difficulty: 2, category: "Clinical Assessment", topic: "Anxiety Disorders" },
  { id: "rp-534", stem: "A client reports persistent auditory hallucinations, paranoid delusions, and disorganized speech for 8 months. The most appropriate diagnosis is:", options: ["Schizophrenia","Brief psychotic disorder","Schizophreniform disorder","Schizoaffective disorder"], correctIndex: 0, rationale: "Schizophrenia requires symptoms for at least 6 months (including active phase of at least 1 month). Schizophreniform is 1-6 months. Brief psychotic disorder is under 1 month.", difficulty: 3, category: "Clinical Assessment", topic: "Psychotic Disorders" },
  { id: "rp-535", stem: "The Columbia Suicide Severity Rating Scale (C-SSRS) assesses:", options: ["Suicidal ideation intensity, behaviors, and lethality of attempts","Depression severity across multiple domains","Substance use disorder severity","Personality disorder traits"], correctIndex: 0, rationale: "The C-SSRS specifically measures suicidal ideation (type, intensity, frequency) and suicidal behavior (attempts, preparatory acts, interrupted/aborted attempts).", difficulty: 2, category: "Clinical Assessment", topic: "Suicide Assessment" },
  { id: "rp-536", stem: "A client presents with alternating periods of elevated mood, decreased need for sleep, and grandiosity lasting 5 days, followed by depressive episodes. The most likely diagnosis is:", options: ["Bipolar II disorder","Bipolar I disorder","Cyclothymic disorder","Major depressive disorder with mixed features"], correctIndex: 0, rationale: "Bipolar II requires at least one hypomanic episode (4+ days) and one major depressive episode. Bipolar I requires a manic episode (7+ days or hospitalization). The 5-day elevated period qualifies as hypomania.", difficulty: 3, category: "Clinical Assessment", topic: "Mood Disorders" },
  { id: "rp-537", stem: "A client endorses persistent emptiness, unstable relationships, identity disturbance, and impulsive spending. Which personality disorder is most consistent with this presentation?", options: ["Borderline personality disorder","Narcissistic personality disorder","Histrionic personality disorder","Antisocial personality disorder"], correctIndex: 0, rationale: "BPD features include chronic emptiness, unstable relationships, identity disturbance, impulsivity, emotional dysregulation, and fear of abandonment.", difficulty: 2, category: "Clinical Assessment", topic: "Personality Disorders" },
  { id: "rp-538", stem: "During a crisis assessment, a client states 'I have pills saved up, and I plan to take them tonight when my roommate leaves.' This statement indicates:", options: ["High risk with specific plan, means, and timeline","Low risk ideation without intent","Moderate risk requiring outpatient follow-up only","Chronic passive suicidal ideation"], correctIndex: 0, rationale: "The presence of a specific plan (pills), access to means (pills saved), and a timeline (tonight) with opportunity (roommate leaving) indicates high acute suicide risk requiring immediate intervention.", difficulty: 2, category: "Crisis Intervention", topic: "Suicide Risk Assessment" },
  { id: "rp-539", stem: "In crisis intervention, the primary goal of the initial contact is to:", options: ["Ensure safety and establish rapport","Complete a comprehensive psychosocial history","Assign a formal psychiatric diagnosis","Develop a long-term treatment plan"], correctIndex: 0, rationale: "In crisis intervention, immediate safety assessment and rapport building are the first priorities. Comprehensive assessment and treatment planning come after stabilization.", difficulty: 1, category: "Crisis Intervention", topic: "Crisis Response" },
  { id: "rp-540", stem: "A therapist is conducting a safety planning intervention. Which element should be included?", options: ["Internal coping strategies the client can use without contacting another person","A detailed analysis of the client's childhood trauma","A complete medication review","A comprehensive diagnostic assessment"], correctIndex: 0, rationale: "Stanley and Brown's Safety Planning Intervention includes warning signs, internal coping strategies, social contacts for distraction, professionals to contact, making the environment safe, and reasons for living.", difficulty: 2, category: "Crisis Intervention", topic: "Safety Planning" },
  { id: "rp-541", stem: "A client who recently lost their spouse presents in acute distress with crying, disbelief, and difficulty functioning at work. The episode has lasted 3 weeks. The most appropriate initial assessment is:", options: ["Normal acute grief response requiring supportive intervention","Major depressive disorder requiring medication","Complicated grief requiring prolonged exposure therapy","Adjustment disorder requiring immediate hospitalization"], correctIndex: 0, rationale: "Three weeks after spousal death, acute grief reactions including intense sadness, disbelief, and functional impairment are within the normal grief trajectory. Supportive intervention is appropriate.", difficulty: 2, category: "Crisis Intervention", topic: "Grief and Loss" },
  { id: "rp-542", stem: "When a client is experiencing a panic attack in session, the therapist should first:", options: ["Guide the client through controlled breathing while providing calm reassurance","Have the client leave the room immediately","Begin processing the underlying cause of the panic","Administer a screening questionnaire"], correctIndex: 0, rationale: "During an active panic attack, grounding and breathing techniques provide immediate relief. Processing underlying causes should wait until the acute episode resolves.", difficulty: 1, category: "Crisis Intervention", topic: "In-Session Crisis" },
  { id: "rp-543", stem: "Psychological first aid (PFA) differs from traditional psychotherapy in that PFA:", options: ["Is designed as immediate, practical support following a disaster or traumatic event","Requires extensive training in psychoanalytic theory","Focuses on long-term symptom reduction","Uses standardized manualized treatment protocols over multiple sessions"], correctIndex: 0, rationale: "PFA provides immediate practical and emotional support after trauma/disaster. It is not therapy but a supportive intervention framework designed for early post-event response.", difficulty: 2, category: "Crisis Intervention", topic: "Disaster Response" },
  { id: "rp-544", stem: "A client being treated for PTSD suddenly becomes unresponsive, stares blankly, and appears frozen during a session. The therapist should:", options: ["Use grounding techniques to help orient the client to the present","Continue the trauma narrative to push through the dissociation","Leave the client alone until they recover spontaneously","Call emergency services immediately"], correctIndex: 0, rationale: "Dissociative episodes during trauma processing require grounding interventions (sensory awareness, orientation to the room) to bring the client back to the present safely.", difficulty: 2, category: "Crisis Intervention", topic: "Dissociation Management" },
  { id: "rp-545", stem: "A mandated reporter suspects child abuse based on a client's disclosure. The therapist should:", options: ["File a report with child protective services as required by law","Wait for physical evidence before reporting","Confront the alleged abuser first","Consult with the child's school before making a decision"], correctIndex: 0, rationale: "Mandated reporters must file when there is reasonable suspicion of abuse. Reports are based on suspicion, not proof. Delaying to gather evidence may put the child at further risk.", difficulty: 1, category: "Crisis Intervention", topic: "Mandated Reporting" },
  { id: "rp-546", stem: "In working with a client from a collectivist culture, a therapist should recognize that the client may:", options: ["Prioritize family harmony over individual autonomy in decision-making","Be more likely to express emotions openly in therapy","Prefer individual therapy over family involvement","View independence from family as a primary treatment goal"], correctIndex: 0, rationale: "Collectivist cultures emphasize group harmony, family obligation, and interdependence. Treatment goals should respect these values rather than imposing Western individualistic frameworks.", difficulty: 2, category: "Cultural Competence", topic: "Cultural Values" },
  { id: "rp-547", stem: "A therapist working with an Indigenous client should be aware that traditional healing practices:", options: ["May be integrated with Western psychotherapy with the client's preference and guidance","Are inferior to evidence-based Western treatments","Should be discouraged in favor of standardized protocols","Are interchangeable across all Indigenous nations"], correctIndex: 0, rationale: "Culturally responsive practice respects and may integrate traditional healing when the client values it. Indigenous practices vary significantly across nations and should not be generalized.", difficulty: 2, category: "Cultural Competence", topic: "Indigenous Populations" },
  { id: "rp-548", stem: "The concept of 'microaggressions' in therapy refers to:", options: ["Brief, commonplace exchanges that communicate derogatory messages to members of marginalized groups","Deliberate acts of discrimination by the therapist","Aggressive therapeutic confrontations","Minor scheduling conflicts between therapist and client"], correctIndex: 0, rationale: "Microaggressions are subtle, often unintentional slights that communicate hostile or derogatory messages. In therapy, they can damage the therapeutic alliance and reinforce marginalization.", difficulty: 2, category: "Cultural Competence", topic: "Microaggressions" },
  { id: "rp-549", stem: "When working with a refugee client who has experienced torture, which cultural consideration is most important?", options: ["Understanding that the client may distrust authority figures including therapists","Assuming the client wants to discuss their torture experience immediately","Using the same PTSD protocol as for all trauma clients","Focusing exclusively on resettlement logistics"], correctIndex: 0, rationale: "Torture survivors may deeply distrust authority figures. Building trust slowly, understanding the political context, and respecting the client's pace are essential cultural considerations.", difficulty: 3, category: "Cultural Competence", topic: "Refugee Populations" },
  { id: "rp-550", stem: "A therapist's awareness of their own cultural biases, values, and assumptions is referred to as:", options: ["Cultural self-awareness","Cultural encapsulation","Ethnic identity development","Acculturation"], correctIndex: 0, rationale: "Cultural self-awareness is the first component of multicultural competence. It involves ongoing examination of one's own cultural conditioning, biases, and worldview.", difficulty: 1, category: "Cultural Competence", topic: "Multicultural Competence" },
  { id: "rp-551", stem: "In Yalom's model of group therapy, which therapeutic factor involves group members gaining hope from seeing others' improvement?", options: ["Instillation of hope","Universality","Altruism","Catharsis"], correctIndex: 0, rationale: "Instillation of hope occurs when group members see others at different stages of recovery, fostering optimism about their own potential for change.", difficulty: 2, category: "Group Therapy", topic: "Therapeutic Factors" },
  { id: "rp-552", stem: "During the storming stage of group development, the therapist should:", options: ["Facilitate open discussion of conflict while maintaining group safety","Avoid acknowledging the conflict to prevent escalation","Remove disruptive members immediately","Return to structured activities to bypass the conflict"], correctIndex: 0, rationale: "The storming stage involves normal conflict as members establish roles and norms. The therapist facilitates constructive conflict resolution, modeling that disagreement can be productive.", difficulty: 3, category: "Group Therapy", topic: "Group Development" },
  { id: "rp-553", stem: "In a process-oriented therapy group, a member monopolizes discussion. The most therapeutic intervention is to:", options: ["Invite the group to reflect on the interpersonal dynamic occurring in the here-and-now","Tell the member to stop talking so much","Ignore the behavior and hope it resolves","Ask the member to leave the group"], correctIndex: 0, rationale: "Process-oriented groups use here-and-now interactions as therapeutic material. Exploring the monopolizing pattern as an interpersonal process benefits both the individual and the group.", difficulty: 3, category: "Group Therapy", topic: "Group Process" },
  { id: "rp-554", stem: "Which type of group therapy is most appropriate for clients in early recovery from substance use disorders?", options: ["Psychoeducational group","Unstructured process group","Psychoanalytic group","Marathon group"], correctIndex: 0, rationale: "Psychoeducational groups provide structure, information, and skill-building appropriate for early recovery. Unstructured process groups may be too emotionally demanding for this stage.", difficulty: 2, category: "Group Therapy", topic: "Substance Use Groups" },
  { id: "rp-555", stem: "A group member discloses that another member contacted them outside of group to discuss a third member's disclosures. The therapist should:", options: ["Address the boundary violation in group by discussing confidentiality agreements and subgrouping","Ignore it since it happened outside the group setting","Terminate both members involved","Discuss it privately with each member and not bring it to the group"], correctIndex: 0, rationale: "Subgrouping and confidentiality breaches should be addressed in the group to maintain safety and reinforce norms. This becomes therapeutic material about boundaries and trust.", difficulty: 3, category: "Group Therapy", topic: "Group Boundaries" },
  { id: "rp-556", stem: "The OARS skills in Motivational Interviewing include:", options: ["Open questions, Affirmations, Reflections, Summaries","Observation, Assessment, Referral, Support","Outcomes, Accountability, Resilience, Sustainability","Openness, Acceptance, Responsiveness, Structure"], correctIndex: 0, rationale: "OARS are the foundational MI skills: Open questions encourage exploration, Affirmations build confidence, Reflections demonstrate understanding, and Summaries consolidate key points.", difficulty: 1, category: "Therapeutic Modalities", topic: "Motivational Interviewing" },
  { id: "rp-557", stem: "A therapist working from an Emotionally Focused Therapy (EFT) framework with a couple identifies a 'pursue-withdraw' cycle. This represents:", options: ["A negative interaction pattern where one partner seeks connection while the other distances","A pattern where both partners equally pursue emotional engagement","A healthy communication dynamic","A behavioral contract between partners"], correctIndex: 0, rationale: "The pursue-withdraw cycle is a common negative interaction pattern in EFT. The pursuer seeks closeness through criticism or demands while the withdrawer distances to manage overwhelming emotions.", difficulty: 2, category: "Therapeutic Modalities", topic: "Couples Therapy" },
  { id: "rp-558", stem: "Structural family therapy's concept of 'enmeshment' describes:", options: ["Extreme emotional closeness with diffuse boundaries between family members","Complete emotional disconnection between family members","Healthy interdependence among family members","A family with rigid, impermeable boundaries"], correctIndex: 0, rationale: "Enmeshment (Minuchin) involves diffuse boundaries where family members are overly involved in each other's lives, limiting individual autonomy. The opposite pole is disengagement.", difficulty: 2, category: "Therapeutic Modalities", topic: "Family Therapy" },
  { id: "rp-559", stem: "In Internal Family Systems (IFS) therapy, 'exiles' are:", options: ["Young, vulnerable parts carrying pain and trauma memories","Parts that protect the system through controlling behaviors","The core Self that leads healing","Parts that manage daily functioning"], correctIndex: 0, rationale: "In IFS, exiles are wounded parts (often from childhood) that carry pain, shame, and trauma. Managers and firefighters are protective parts that try to keep exiles suppressed.", difficulty: 3, category: "Therapeutic Modalities", topic: "IFS" },
  { id: "rp-560", stem: "Prolonged Exposure therapy for PTSD involves:", options: ["Repeated recounting of the traumatic memory (imaginal exposure) and approaching avoided situations (in vivo exposure)","Brief one-session exposure to feared stimuli","Medication management combined with relaxation training only","Cognitive restructuring without any exposure components"], correctIndex: 0, rationale: "Prolonged Exposure includes imaginal exposure (detailed trauma narrative repeated across sessions) and in vivo exposure to safe but avoided trauma-related situations.", difficulty: 3, category: "Therapeutic Modalities", topic: "Trauma Therapy" },
  { id: "rp-561", stem: "A therapist learns that their client is also seeing another therapist for the same issues without either therapist's knowledge. The therapist should:", options: ["Discuss with the client and request a release to coordinate care","Immediately terminate treatment","Continue treatment without addressing it","Report the client to their insurance company"], correctIndex: 0, rationale: "Splitting treatment without coordination can be counterproductive or harmful. The therapist should discuss this openly and seek coordination to ensure effective, non-contradictory care.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Coordination of Care" },
  { id: "rp-562", stem: "The ethical principle of nonmaleficence requires therapists to:", options: ["Avoid causing harm to clients","Promote client welfare actively","Treat all clients equally","Maintain honest communication"], correctIndex: 0, rationale: "Nonmaleficence ('do no harm') is the obligation to avoid actions that could harm clients. It is distinct from beneficence, which involves actively promoting welfare.", difficulty: 1, category: "Ethics & Professional Practice", topic: "Core Principles" },
  { id: "rp-563", stem: "A therapist accepts a referral for a client whose presenting problem is outside the therapist's area of expertise. The most ethical action is to:", options: ["Refer to a qualified provider or obtain appropriate supervision and training","Accept the client and learn as you go","Treat the client using techniques from a different modality you are trained in","Accept and hope the issues fall within your existing knowledge"], correctIndex: 0, rationale: "Practicing outside one's competence violates ethical standards. The therapist should refer to a qualified provider or, if appropriate, seek supervision and training before proceeding.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Scope of Practice" },
  { id: "rp-564", stem: "After a natural disaster, which phase of crisis response involves long-term community rebuilding and addressing chronic mental health needs?", options: ["Recovery phase","Impact phase","Heroic phase","Honeymoon phase"], correctIndex: 0, rationale: "The recovery phase involves long-term rebuilding, addressing ongoing mental health needs, and restoring community functioning. The impact phase is the immediate disaster period.", difficulty: 2, category: "Crisis Intervention", topic: "Disaster Response" },
  { id: "rp-565", stem: "When assessing suicide risk, which demographic factor is associated with the highest completed suicide rate in the United States?", options: ["White males over age 65","Adolescent females","Middle-aged women","Young adult males age 18-25"], correctIndex: 0, rationale: "White males over 65 have the highest completed suicide rate in the US, though they may present less frequently for treatment. Assessment must not rely on demographics alone.", difficulty: 3, category: "Crisis Intervention", topic: "Suicide Epidemiology" },
  { id: "rp-566", stem: "A client in a domestic violence situation asks the therapist to develop a safety plan. An essential component is:", options: ["Identifying a safe place to go and packing an emergency bag with essential documents","Confronting the abuser in a couples session","Filing for divorce immediately","Calling the police during a calm period to file a preemptive report"], correctIndex: 0, rationale: "Domestic violence safety planning includes escape routes, safe locations, emergency documents, financial resources, and safety strategies. Confronting the abuser can escalate danger.", difficulty: 2, category: "Crisis Intervention", topic: "Domestic Violence" },
  { id: "rp-567", stem: "The concept of 'intersectionality' in therapy recognizes that:", options: ["A person's multiple social identities interact to create unique experiences of privilege and oppression","All members of a cultural group share identical experiences","Cultural identity is fixed and unchanging","Therapists should focus on only one aspect of identity at a time"], correctIndex: 0, rationale: "Intersectionality (Crenshaw) acknowledges that overlapping identities (race, gender, class, sexuality, disability) interact to shape unique experiences of marginalization and privilege.", difficulty: 2, category: "Cultural Competence", topic: "Intersectionality" },
  { id: "rp-568", stem: "When working with a client who uses a language interpreter, the therapist should:", options: ["Speak directly to the client and maintain eye contact with the client, not the interpreter","Direct all conversation through the interpreter","Use family members as interpreters when possible","Simplify clinical concepts to avoid interpreter confusion"], correctIndex: 0, rationale: "Best practice is to speak directly to the client, maintaining the therapeutic relationship. Professional interpreters (not family members) should be used to ensure accuracy and confidentiality.", difficulty: 2, category: "Cultural Competence", topic: "Language Access" },
  { id: "rp-569", stem: "A therapist working with an LGBTQ+ adolescent should be aware that:", options: ["Family rejection is a significant risk factor for depression, suicidality, and homelessness in this population","Sexual orientation can be changed through therapeutic intervention","All LGBTQ+ youth experience the same challenges","Coming out to family always improves mental health outcomes"], correctIndex: 0, rationale: "Research consistently shows family rejection significantly increases risk for depression, suicide attempts, substance use, and homelessness in LGBTQ+ youth. Family acceptance is a protective factor.", difficulty: 2, category: "Cultural Competence", topic: "LGBTQ+ Populations" },
  { id: "rp-570", stem: "Countertransference that stems from a therapist's own unresolved cultural biases is called:", options: ["Cultural countertransference","Projective identification","Therapeutic impasse","Structural dissociation"], correctIndex: 0, rationale: "Cultural countertransference occurs when a therapist's unexamined cultural biases, stereotypes, or cultural experiences influence their reactions to clients from different backgrounds.", difficulty: 3, category: "Cultural Competence", topic: "Therapist Self-Awareness" },
  { id: "rp-571", stem: "In group therapy, 'universality' as a therapeutic factor refers to:", options: ["Members discovering that their problems and feelings are shared by others in the group","The group applying universal treatment principles to all members","The therapist using the same interventions for everyone","Members agreeing on universal group rules"], correctIndex: 0, rationale: "Universality (Yalom) provides relief when members realize they are not alone in their struggles. This reduces isolation and shame, which are common maintaining factors in mental health conditions.", difficulty: 1, category: "Group Therapy", topic: "Therapeutic Factors" },
  { id: "rp-572", stem: "When screening potential group members, which client would be LEAST appropriate for an outpatient interpersonal process group?", options: ["A client in active psychosis with paranoid delusions about other people","A client with social anxiety who wants to improve relationships","A client with depression and interpersonal difficulties","A client with adjustment disorder after a divorce"], correctIndex: 0, rationale: "Active psychosis with paranoia is a contraindication for process groups, as the client cannot reliably engage in interpersonal learning and may disrupt group cohesion and safety.", difficulty: 2, category: "Group Therapy", topic: "Group Screening" },
  { id: "rp-573", stem: "A behavioral activation plan for depression primarily involves:", options: ["Scheduling meaningful activities to counteract withdrawal and avoidance","Analyzing the unconscious meaning of depressive symptoms","Prescribing antidepressant medication","Interpreting dream content related to loss"], correctIndex: 0, rationale: "Behavioral activation addresses the withdrawal-depression cycle by systematically scheduling valued activities. Research shows it is as effective as full CBT for depression.", difficulty: 2, category: "Therapeutic Modalities", topic: "Behavioral Therapy" },
  { id: "rp-574", stem: "According to attachment theory, an adult with dismissive-avoidant attachment style in therapy may:", options: ["Minimize emotional needs, intellectualize problems, and have difficulty accessing feelings","Cling to the therapist and fear abandonment","Rapidly form a strong therapeutic alliance","Alternate unpredictably between seeking closeness and pushing away"], correctIndex: 0, rationale: "Dismissive-avoidant individuals suppress attachment needs, value self-reliance, and may intellectualize in therapy. Building emotional engagement requires patience and attunement.", difficulty: 3, category: "Clinical Assessment", topic: "Attachment Theory" },
  { id: "rp-575", stem: "The biopsychosocial model of assessment includes evaluating:", options: ["Biological, psychological, and social factors contributing to the client's presentation","Only neurological and biological factors","Exclusively psychological and behavioral patterns","Social determinants of health alone"], correctIndex: 0, rationale: "The biopsychosocial model (Engel) integrates biological (genetics, medical conditions), psychological (cognition, emotion, behavior), and social (relationships, culture, socioeconomic) factors.", difficulty: 1, category: "Clinical Assessment", topic: "Assessment Models" },
  { id: "rp-576", stem: "A client taking an SSRI reports sudden onset of confusion, agitation, rapid heart rate, tremor, and muscle rigidity. The therapist should:", options: ["Refer immediately to emergency medical services for possible serotonin syndrome","Interpret the symptoms as a panic attack and use breathing techniques","Suggest the client reduce their medication dose","Schedule a follow-up appointment for next week"], correctIndex: 0, rationale: "These symptoms are consistent with serotonin syndrome, a potentially life-threatening condition. Immediate emergency medical referral is essential.", difficulty: 3, category: "Clinical Assessment", topic: "Psychopharmacology Awareness" },
  { id: "rp-577", stem: "Which defense mechanism involves attributing one's own unacceptable thoughts or feelings to another person?", options: ["Projection","Reaction formation","Sublimation","Rationalization"], correctIndex: 0, rationale: "Projection involves unconsciously attributing one's own unacceptable thoughts, feelings, or impulses to others. Reaction formation converts impulses into their opposite.", difficulty: 1, category: "Clinical Assessment", topic: "Defense Mechanisms" },
  { id: "rp-578", stem: "The DSM-5 specifier 'with anxious distress' in major depressive disorder indicates:", options: ["Prominent anxiety symptoms co-occurring with the depressive episode","A separate anxiety disorder diagnosis","Anxiety caused exclusively by medication side effects","Historical anxiety that has since resolved"], correctIndex: 0, rationale: "The anxious distress specifier indicates clinically significant anxiety during a depressive episode (feeling keyed up, restless, difficulty concentrating, fear of losing control). It affects treatment planning.", difficulty: 3, category: "Clinical Assessment", topic: "DSM-5 Specifiers" },
  { id: "rp-579", stem: "A therapist notices that a depressed client consistently attributes failures to internal, stable, global causes. This cognitive pattern is known as:", options: ["Depressive attributional style","External locus of control","Cognitive dissonance","Fundamental attribution error"], correctIndex: 0, rationale: "Seligman's depressive attributional style involves explaining negative events as internal ('it's me'), stable ('it will always be this way'), and global ('it affects everything').", difficulty: 3, category: "Clinical Assessment", topic: "Cognitive Patterns" },
  { id: "rp-580", stem: "In a DBT skills group, which component is NOT typically included?", options: ["Individual processing of personal trauma narratives","Teaching and practicing mindfulness exercises","Homework review of skill application","Role-playing interpersonal effectiveness skills"], correctIndex: 0, rationale: "DBT skills groups focus on teaching and practicing skills (mindfulness, distress tolerance, emotion regulation, interpersonal effectiveness). Individual trauma processing occurs in individual therapy.", difficulty: 2, category: "Group Therapy", topic: "Skills Groups" },
  { id: "rp-581", stem: "When co-leading a therapy group, the co-therapists should:", options: ["Discuss group dynamics and process together after each session","Compete for group members' allegiance","Avoid discussing the group outside of sessions","Always agree with each other during sessions to present a united front"], correctIndex: 0, rationale: "Regular debriefing between co-leaders ensures consistent approach, processes countertransference, and addresses group dynamics. Modeling healthy disagreement can be therapeutically valuable.", difficulty: 2, category: "Group Therapy", topic: "Co-Leadership" },
  { id: "rp-582", stem: "In Bowenian family therapy, 'differentiation of self' refers to:", options: ["The ability to maintain one's own thinking and emotional functioning in the presence of family pressure","Complete emotional separation from the family of origin","The family's ability to distinguish between members","A technique for externalizing problems"], correctIndex: 0, rationale: "Differentiation is the capacity to think independently while remaining emotionally connected. It is not about cutting off from family but about managing reactivity within relationships.", difficulty: 3, category: "Therapeutic Modalities", topic: "Family Therapy" },
  { id: "rp-583", stem: "Motivational Interviewing's concept of 'change talk' includes which type of client statement?", options: ["'I need to stop drinking before I lose my family'","'I don't think my drinking is really a problem'","'Everyone drinks like I do'","'My partner is overreacting about my use'"], correctIndex: 0, rationale: "Change talk includes statements expressing Desire, Ability, Reason, Need, Commitment, Activation, or Taking steps toward change (DARN-CAT). The statement expresses need and reason.", difficulty: 2, category: "Therapeutic Modalities", topic: "Motivational Interviewing" },
  { id: "rp-584", stem: "Schema therapy integrates elements from which therapeutic approaches?", options: ["CBT, attachment theory, Gestalt, and psychodynamic therapy","Exclusively behavioral and pharmacological approaches","Only humanistic and existential frameworks","Strictly psychoanalytic techniques"], correctIndex: 0, rationale: "Schema therapy (Young) integrates cognitive-behavioral techniques, attachment theory, Gestalt experiential techniques, and psychodynamic concepts to address early maladaptive schemas.", difficulty: 3, category: "Therapeutic Modalities", topic: "Integrative Approaches" },
  { id: "rp-585", stem: "A therapist uses a technique where the client rates their belief in a negative thought on a 0-100 scale before and after examining evidence. This is:", options: ["Cognitive restructuring with thought records","Progressive muscle relaxation","Free association","Systematic desensitization"], correctIndex: 0, rationale: "Rating belief strength before and after examining evidence is a core CBT technique using thought records. It helps clients see objective changes in their appraisals.", difficulty: 2, category: "Therapeutic Modalities", topic: "CBT" },
  { id: "rp-586", stem: "A therapist provides therapy services via video conferencing to a client in another state. Which ethical issue is most critical?", options: ["Licensure requirements in the client's state of residence","The quality of the video connection","The therapist's preference for in-person sessions","Insurance billing codes for telehealth"], correctIndex: 0, rationale: "Therapists must be licensed in the jurisdiction where the client is physically located during the session. Practicing without proper licensure is an ethical and legal violation.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Telehealth Ethics" },
  { id: "rp-587", stem: "The ethical concept of 'justice' in psychotherapy practice includes:", options: ["Fair and equitable access to mental health services regardless of background","Ensuring the therapist is compensated fairly","Punishing clients who violate treatment agreements","Maintaining the therapist's right to choose clients based on personal preference"], correctIndex: 0, rationale: "Justice requires fair treatment and equitable access to services. It addresses systemic barriers and the therapist's responsibility to advocate for underserved populations.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Core Principles" },
  { id: "rp-588", stem: "When documenting therapy sessions, progress notes should include:", options: ["Clinically relevant information about the session, interventions used, and client's response","Verbatim transcripts of the entire session","The therapist's personal opinions about the client's character","Detailed descriptions of the client's physical appearance each session"], correctIndex: 0, rationale: "Progress notes document clinically relevant content, interventions, client response, and treatment progress. They should be objective, concise, and focused on treatment-relevant material.", difficulty: 1, category: "Ethics & Professional Practice", topic: "Documentation" },
  { id: "rp-589", stem: "A client asks to connect with the therapist on social media. The therapist should:", options: ["Decline and discuss the therapeutic rationale for maintaining boundaries","Accept to strengthen the therapeutic alliance","Accept but restrict what the client can see","Ignore the request without discussing it"], correctIndex: 0, rationale: "Social media connections constitute a boundary crossing that can compromise therapeutic objectivity and confidentiality. The therapist should decline and explore the meaning of the request therapeutically.", difficulty: 1, category: "Ethics & Professional Practice", topic: "Boundaries" },
  { id: "rp-590", stem: "Somatic Experiencing therapy addresses trauma primarily through:", options: ["Tracking and releasing bodily sensations associated with traumatic stress","Cognitive restructuring of trauma-related thoughts","Extended verbal narration of traumatic events","Pharmacological intervention combined with talk therapy"], correctIndex: 0, rationale: "Somatic Experiencing (Levine) focuses on bodily sensations (felt sense) to discharge trapped survival energy. It works with the autonomic nervous system rather than cognitive processing.", difficulty: 3, category: "Therapeutic Modalities", topic: "Somatic Therapy" },
  { id: "rp-591", stem: "The 'window of tolerance' concept describes:", options: ["The optimal zone of arousal where a person can process emotions and think clearly","The therapist's patience threshold during difficult sessions","The time limit for trauma exposure in a single session","A technique for managing angry clients"], correctIndex: 0, rationale: "The window of tolerance (Siegel) is the zone of optimal arousal between hyperarousal (fight/flight) and hypoarousal (freeze/collapse). Therapy aims to expand this window.", difficulty: 2, category: "Clinical Assessment", topic: "Trauma Neuroscience" },
  { id: "rp-592", stem: "According to Prochaska and DiClemente's Stages of Change model, a client who acknowledges their drinking is problematic but has not yet committed to change is in which stage?", options: ["Contemplation","Precontemplation","Preparation","Action"], correctIndex: 0, rationale: "Contemplation involves awareness of the problem and consideration of change, but ambivalence persists. Precontemplation lacks awareness, and preparation involves planning specific steps.", difficulty: 1, category: "Clinical Assessment", topic: "Stages of Change" },
  { id: "rp-593", stem: "A couple presents with chronic conflict. The Gottman Method identifies which behavior as the most destructive to relationships?", options: ["Contempt","Criticism","Defensiveness","Stonewalling"], correctIndex: 0, rationale: "Gottman's research identifies contempt (disrespect, mockery, eye-rolling) as the strongest predictor of relationship dissolution among the 'Four Horsemen.'", difficulty: 2, category: "Therapeutic Modalities", topic: "Couples Therapy" },
  { id: "rp-594", stem: "In existential therapy, 'existential anxiety' is viewed as:", options: ["An inevitable part of human existence that can be a catalyst for authentic living","A pathological condition requiring medication","A symptom to be eliminated through behavioral techniques","Evidence of early childhood trauma"], correctIndex: 0, rationale: "Existential therapy views anxiety about death, freedom, isolation, and meaninglessness as inherent to human existence. Confronting these concerns can lead to more authentic, meaningful living.", difficulty: 2, category: "Therapeutic Modalities", topic: "Existential Therapy" },
  { id: "rp-595", stem: "A therapist using the 'Socratic method' in CBT is:", options: ["Asking guided questions to help the client discover inconsistencies in their thinking","Lecturing the client on rational thinking patterns","Directly telling the client what to think","Using confrontational techniques to break through denial"], correctIndex: 0, rationale: "Socratic questioning uses guided discovery through strategic questions rather than direct challenging. The client arrives at new perspectives through their own reasoning process.", difficulty: 1, category: "Therapeutic Modalities", topic: "CBT" },
  { id: "rp-596", stem: "A group therapy member reveals a secret that affects another group member who is not present. The therapist should:", options: ["Redirect the discussion and address confidentiality, noting that discussing absent members is a group norm violation","Allow the disclosure to continue without intervention","Share the information with the absent member privately","Ask the group to vote on whether the information should be shared"], correctIndex: 0, rationale: "Talking about absent members violates group norms and safety. The therapist should redirect, reinforce confidentiality expectations, and explore the process dynamics.", difficulty: 3, category: "Group Therapy", topic: "Group Norms" },
  { id: "rp-597", stem: "Harm reduction as a therapeutic approach with substance use involves:", options: ["Meeting clients where they are and reducing negative consequences without requiring abstinence","Enabling continued substance use without any intervention","Withholding treatment until the client commits to abstinence","Providing substances in a controlled therapeutic setting"], correctIndex: 0, rationale: "Harm reduction pragmatically reduces negative consequences of substance use while respecting client autonomy. It does not require abstinence as a precondition for treatment.", difficulty: 2, category: "Therapeutic Modalities", topic: "Substance Use Treatment" },
  { id: "rp-598", stem: "A newly licensed therapist should seek supervision when:", options: ["Encountering a clinical situation that exceeds their training or experience","They have been in practice for less than one year only","A client directly requests that the therapist be supervised","They feel completely confident in their clinical skills"], correctIndex: 0, rationale: "Seeking supervision or consultation for challenging cases is an ethical obligation throughout one's career, not just during early practice. It ensures client welfare and professional growth.", difficulty: 1, category: "Ethics & Professional Practice", topic: "Supervision" },
  { id: "rp-599", stem: "The therapeutic concept of 'rupture and repair' in the therapeutic alliance refers to:", options: ["Inevitable breakdowns in the therapeutic relationship that, when addressed, can deepen the alliance","A technique for intentionally frustrating the client to provoke insight","The process of termination and re-engagement in therapy","Replacing one therapeutic modality with another when treatment stalls"], correctIndex: 0, rationale: "Alliance ruptures (disagreements, misunderstandings, breaches) are inevitable. Skillful repair strengthens the relationship and provides a corrective relational experience for the client.", difficulty: 3, category: "Therapeutic Modalities", topic: "Therapeutic Alliance" },
  { id: "rp-600", stem: "When treating a client with comorbid PTSD and substance use disorder, current best practice recommends:", options: ["Integrated treatment addressing both conditions simultaneously","Treating substance use first and delaying trauma work until sobriety is established","Treating PTSD first regardless of substance use severity","Referring to separate specialists who do not coordinate care"], correctIndex: 0, rationale: "Research supports integrated treatment (e.g., Seeking Safety) addressing both conditions concurrently. Sequential treatment can perpetuate the cycle where each condition maintains the other.", difficulty: 3, category: "Therapeutic Modalities", topic: "Comorbid Treatment" }
];
